class Solution:
    def largest1BorderedSquare(self, grid):
        m, n = len(grid), len(grid[0])
        best = 0
        for i in range(m):
            for j in range(n):
                max_side = min(m - i, n - j)
                for side in range(max_side, 0, -1):
                    if side <= best:
                        break
                    ok = True
                    for k in range(side):
                        if grid[i][j + k] != 1 or grid[i + side - 1][j + k] != 1 or grid[i + k][j] != 1 or grid[i + k][j + side - 1] != 1:
                            ok = False
                            break
                    if ok:
                        best = max(best, side)
                        break
        return best * best

