var largest1BorderedSquare = function(grid) {
    const m = grid.length, n = grid[0].length;
    const left = Array.from({ length: m }, () => new Array(n).fill(0));
    const up = Array.from({ length: m }, () => new Array(n).fill(0));
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            if (grid[i][j] === 1) {
                left[i][j] = (j > 0 ? left[i][j - 1] : 0) + 1;
                up[i][j] = (i > 0 ? up[i - 1][j] : 0) + 1;
            }
        }
    }
    let best = 0;
    for (let i = m - 1; i >= 0; i--) {
        for (let j = n - 1; j >= 0; j--) {
            let side = Math.min(left[i][j], up[i][j]);
            while (side > best) {
                if (up[i][j - side + 1] >= side && left[i - side + 1][j] >= side) {
                    best = side;
                    break;
                }
                side--;
            }
        }
    }
    return best * best;
};
